import OpenAI from 'openai';
import { VexVerifier } from 'vex-sdk';

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
const vex = new VexVerifier({ apiKey: 'vex_gov_key' });

const verifierSchema = {
  type: 'object',
  properties: {
    files_retrieved: { type: 'array', maxItems: 5 },
    context_tokens: { type: 'number', maximum: 100000 },
    no_classified_data: { type: 'boolean' }
  }
};

// Handle run.completed webhook
export async function handleRunComplete(event: any) {
  const run = event.data.object;

  const verification = await vex.verify({
    runId: run.id,
    toolCalls: run.last_message?.content[0]?.annotations || [],
    threadMessages: run.thread.messages.length,
    schema: verifierSchema,
    policy: 'fisma-high'
  });

  if (!verification.valid) {
    console.error('FISMA violation:', verification.issues);
    // Trigger incident response
    await openai.beta.threads.messages.create(run.thread.id, {
      role: 'assistant',
      content: 'Compliance review required. Decision paused.'
    });
    throw new Error('Blocked by Vex');
  }

  return { status: 'compliant' };
}

