from openai import OpenAI
from vex_sdk import Verifier, Policy

client = OpenAI()
vex = Verifier(api_key='vex_gov_key')

# NIST 800-53 compliant function schema
gov_functions = [
    {
        "type": "function",
        "function": {
            "name": "check_citizen_eligibility",
            "description": "Check FedRAMP-approved eligibility",
            "parameters": {
                "type": "object",
                "properties": {
                    "ssn": {"type": "string", "pattern": "^\d{3}-\d{2}-\d{4}$"},
                    "classification": {"type": "string", "enum": ["UNCLASSIFIED"]}
                },
                "required": ["ssn"]
            }
        }
    }
]

@vex.guard('nist-800-53-ac-2')
def validate_fn_call(tool_call):
    """Verify function arguments match government schema"""
    result = vex.verify({
        'arguments': tool_call.function.arguments,
        'name': tool_call.function.name,
        'allowed_endpoints': ['api.fedramp.gov/eligibility']
    })
    return result.valid

thread = client.beta.threads.create()
run = client.beta.threads.runs.create(
    thread_id=thread.id,
    assistant_id="asst_gov_benefits",
    tools=gov_functions
)

# Poll and verify
while run.status != 'completed':
    run = client.beta.threads.runs.retrieve(thread_id=thread.id, run_id=run.id)
    if run.status == 'requires_action':
        for tool_call in run.required_action.submit_tool_outputs.tool_calls:
            if not validate_fn_call(tool_call):
                # Block execution
                client.beta.threads.runs.submit_tool_outputs(
                    thread_id=thread.id,
                    run_id=run.id,
                    tool_outputs=[{"tool_call_id": tool_call.id, "output": "BLOCKED: Invalid schema"}]
                )
